-- =====================================================================
-- MIGRASI: Fitur Pemenuhan Standar Alat Labkesmas
-- Jalankan SEKALI pada database produksi yang SUDAH ada (via phpMyAdmin > Import/SQL).
-- Menambah kolom labkesmas.jenis_lab, tabel alat/standar_alat/inventaris_alat,
-- dan mengisi katalog + standar dari KMK No. HK.01.07/MENKES/1801/2024.
-- =====================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

ALTER TABLE `labkesmas` ADD COLUMN `jenis_lab` varchar(255) DEFAULT NULL AFTER `tier_labkesmas`;

CREATE TABLE `alat` (
  `id` char(36) NOT NULL,
  `nama_alat` varchar(255) NOT NULL,
  `kategori` varchar(255) NOT NULL,
  `keterangan` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `alat_kategori_index` (`kategori`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `standar_alat` (
  `id` char(36) NOT NULL,
  `alat_id` char(36) NOT NULL,
  `tier` tinyint unsigned NOT NULL,
  `jenis_lab` varchar(255) NOT NULL DEFAULT 'umum',
  `jumlah_minimal` int unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_standar_alat` (`alat_id`,`tier`,`jenis_lab`),
  KEY `standar_alat_tier_jenis_lab_index` (`tier`,`jenis_lab`),
  CONSTRAINT `standar_alat_alat_id_foreign` FOREIGN KEY (`alat_id`) REFERENCES `alat` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `inventaris_alat` (
  `id` char(36) NOT NULL,
  `labkesmas_id` char(36) NOT NULL,
  `alat_id` char(36) NOT NULL,
  `jumlah` int unsigned NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_inventaris_alat` (`labkesmas_id`,`alat_id`),
  KEY `inventaris_alat_alat_id_foreign` (`alat_id`),
  CONSTRAINT `inventaris_alat_labkesmas_id_foreign` FOREIGN KEY (`labkesmas_id`) REFERENCES `labkesmas` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventaris_alat_alat_id_foreign2` FOREIGN KEY (`alat_id`) REFERENCES `alat` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Katalog alat (155) 

